/**
 * Main app.js entry point
 * Loaded by Vite and compiled into public/build
 */

// Import bootstrap (Axios + Echo setup)
import "/resources/js/bootstrap.js";

// Example: log that JS is loaded
console.log("🚀 App.js loaded");

// If you want to subscribe to notifications here instead of Blade:
if (window.Laravel && window.Laravel.userId) {
    const userId = window.Laravel.userId;

    window.Echo.private(`App.Models.User.${userId}`)
        .notification((notification) => {
            console.log("📩 New notification received:", notification);

            let list = document.getElementById("notificationList");
            if (list) {
                list.innerHTML = `
                    <a class="dropdown-item" href="javascript:;">
                        <div class="d-flex align-items-center">
                            <div class="user-online">
                                ${notification.profile_picture ? `<img src="${notification.profile_picture}" class="msg-avatar" alt="user avatar">` : ""}
                            </div>
                            <div class="flex-grow-1">
                                <h6 class="msg-name">${notification.meta_name}
                                    <span class="msg-time float-end">
                                        <button class="btn btn-xs btn-danger" onclick="markRead('${notification.id}')">Mark Read</button>
                                    </span>
                                </h6>
                                <p class="msg-info">${notification.message}</p>
                            </div>
                        </div>
                    </a>
                ` + list.innerHTML;
            }

            // update unread count
            let unread = document.getElementById("unreadCount");
            if (unread) {
                unread.innerText = parseInt(unread.innerText || 0) + 1;
            }
        });
}

